    38→// HeaderMatcher will consist of:
    39→//   header_match_specifier which can be any one of exact_match, regex_match, range_match,
    40→//   present_match, prefix_match or suffix_match.
    41→//   Each of these also can be inverted with the invert_match option.
    42→//   Absence of these options implies empty header value match based on header presence.
    43→//   a.exact_match: value will be used for exact string matching.
    44→//   b.regex_match: Match will succeed if header value matches the value specified here.
    45→//   c.range_match: Match will succeed if header value lies within the range specified
    46→//     here, using half open interval semantics [start,end).
    47→//   d.present_match: Match will succeed if the header is present.
    48→//   f.prefix_match: Match will succeed if header value matches the prefix value specified here.
    49→//   g.suffix_match: Match will succeed if header value matches the suffix value specified here.
    50→HeaderUtility::HeaderData::HeaderData(const envoy::config::route::v3::HeaderMatcher& config,
    51→                                      Server::Configuration::CommonFactoryContext& factory_context)
    52→    : name_(config.name()), invert_match_(config.invert_match()),
    53→      treat_missing_as_empty_(config.treat_missing_header_as_empty()) {
    54→  switch (config.header_match_specifier_case()) {
    55→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kExactMatch:
    56→    header_match_type_ = HeaderMatchType::Value;
    57→    value_ = config.exact_match();
    58→    break;
    59→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kSafeRegexMatch:
    60→    header_match_type_ = HeaderMatchType::Regex;
    61→    regex_ = Regex::Utility::parseRegex(config.safe_regex_match(), factory_context.regexEngine());
    62→    break;
    63→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kRangeMatch:
    64→    header_match_type_ = HeaderMatchType::Range;
    65→    range_.set_start(config.range_match().start());
    66→    range_.set_end(config.range_match().end());
    67→    break;
    68→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kPresentMatch:
    69→    header_match_type_ = HeaderMatchType::Present;
    70→    present_ = config.present_match();
    71→    break;
    72→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kPrefixMatch:
    73→    header_match_type_ = HeaderMatchType::Prefix;
    74→    value_ = config.prefix_match();
    75→    break;
    76→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kSuffixMatch:
    77→    header_match_type_ = HeaderMatchType::Suffix;
    78→    value_ = config.suffix_match();
    79→    break;
    80→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kContainsMatch:
    81→    header_match_type_ = HeaderMatchType::Contains;
    82→    value_ = config.contains_match();
    83→    break;
    84→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kStringMatch:
    85→    header_match_type_ = HeaderMatchType::StringMatch;
    86→    string_match_ =
    87→        std::make_unique<Matchers::StringMatcherImpl<envoy::type::matcher::v3::StringMatcher>>(
    88→            config.string_match(), factory_context);
    89→    break;
    90→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::
    91→      HEADER_MATCH_SPECIFIER_NOT_SET:
    92→    FALLTHRU;
    93→  default:
    94→    header_match_type_ = HeaderMatchType::Present;
    95→    present_ = true;
    96→    break;
    97→  }
    98→}
