   114→HeaderUtility::GetAllOfHeaderAsStringResult
   115→HeaderUtility::getAllOfHeaderAsString(const HeaderMap::GetResult& header_value,
   116→                                      absl::string_view separator) {
   117→  GetAllOfHeaderAsStringResult result;
   118→  // In this case we concatenate all found headers using a delimiter before performing the
   119→  // final match. We use an InlinedVector of absl::string_view to invoke the optimized join
   120→  // algorithm. This requires a copying phase before we invoke join. The 3 used as the inline
   121→  // size has been arbitrarily chosen.
   122→  // TODO(mattklein123): Do we need to normalize any whitespace here?
   123→  absl::InlinedVector<absl::string_view, 3> string_view_vector;
   124→  string_view_vector.reserve(header_value.size());
   125→  for (size_t i = 0; i < header_value.size(); i++) {
   126→    string_view_vector.push_back(header_value[i]->value().getStringView());
   127→  }
   128→  result.result_backing_string_ = absl::StrJoin(string_view_vector, separator);
   129→
   130→  return result;
   131→}
   132→
   133→HeaderUtility::GetAllOfHeaderAsStringResult
   134→HeaderUtility::getAllOfHeaderAsString(const HeaderMap& headers, const Http::LowerCaseString& key,
   135→                                      absl::string_view separator) {
   136→  GetAllOfHeaderAsStringResult result;
   137→  const auto header_value = headers.get(key);
   138→
   139→  if (header_value.empty()) {
   140→    // Empty for clarity. Avoid handling the empty case in the block below if the runtime feature
   141→    // is disabled.
   142→  } else if (header_value.size() == 1) {
   143→    result.result_ = header_value[0]->value().getStringView();
   144→  } else {
   145→    return getAllOfHeaderAsString(header_value, separator);
   146→  }
   147→
   148→  return result;
   149→}
   150→
   151→bool HeaderUtility::matchHeaders(const HeaderMap& request_headers, const HeaderData& header_data) {
   152→  const auto header_value = getAllOfHeaderAsString(request_headers, header_data.name_);
   153→
   154→  if (!header_value.result().has_value() && !header_data.treat_missing_as_empty_) {
   155→    if (header_data.invert_match_) {
   156→      return header_data.header_match_type_ == HeaderMatchType::Present && header_data.present_;
   157→    } else {
   158→      return header_data.header_match_type_ == HeaderMatchType::Present && !header_data.present_;
   159→    }
   160→  }
   161→
   162→  // If the header does not have value and the result is not returned in the
   163→  // code above, it means treat_missing_as_empty_ is set to true and we should
   164→  // treat the header value as empty.
   165→  const auto value = header_value.result().has_value() ? header_value.result().value() : "";
   166→  bool match;
   167→  switch (header_data.header_match_type_) {
   168→  case HeaderMatchType::Value:
   169→    match = header_data.value_.empty() || value == header_data.value_;
   170→    break;
   171→  case HeaderMatchType::Regex:
   172→    match = header_data.regex_->match(value);
   173→    break;
   174→  case HeaderMatchType::Range: {
   175→    int64_t header_int_value = 0;
   176→    match = absl::SimpleAtoi(value, &header_int_value) &&
   177→            header_int_value >= header_data.range_.start() &&
   178→            header_int_value < header_data.range_.end();
   179→    break;
   180→  }
   181→  case HeaderMatchType::Present:
   182→    match = header_data.present_;
   183→    break;
   184→  case HeaderMatchType::Prefix:
   185→    match = absl::StartsWith(value, header_data.value_);
   186→    break;
   187→  case HeaderMatchType::Suffix:
   188→    match = absl::EndsWith(value, header_data.value_);
   189→    break;
   190→  case HeaderMatchType::Contains:
   191→    match = absl::StrContains(value, header_data.value_);
   192→    break;
   193→  case HeaderMatchType::StringMatch:
   194→    match = header_data.string_match_->match(value);
   195→    break;
   196→  }
   197→
   198→  return match != header_data.invert_match_;
   199→}
