   326→#ifdef ENVOY_ENABLE_HTTP_DATAGRAMS
   327→bool HeaderUtility::isCapsuleProtocol(const RequestOrResponseHeaderMap& headers) {
   328→  Http::HeaderMap::GetResult capsule_protocol =
   329→      headers.get(Envoy::Http::LowerCaseString("Capsule-Protocol"));
   330→  // When there are multiple Capsule-Protocol header entries, it returns false. RFC 9297 specifies
   331→  // that non-boolean value types must be ignored. If there are multiple header entries, the value
   332→  // type becomes a List so the header field must be ignored.
   333→  if (capsule_protocol.size() != 1) {
   334→    return false;
   335→  }
   336→  // Parses the header value and extracts the boolean value ignoring parameters.
   337→  absl::optional<quiche::structured_headers::ParameterizedItem> header_item =
   338→      quiche::structured_headers::ParseItem(capsule_protocol[0]->value().getStringView());
   339→  return header_item && header_item->item.is_boolean() && header_item->item.GetBoolean();
   340→}
   341→#endif
