   498→      return absl::InvalidArgumentError(
   499→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Host.get()));
   500→    }
   501→    if (headers.Path() && !headers.Protocol()) {
   502→      // Path and Protocol header should only be present for CONNECT for upgrade style CONNECT.
   503→      return absl::InvalidArgumentError(
   504→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Protocol.get()));
   505→    }
   506→    if (!headers.Path() && headers.Protocol()) {
   507→      // Path and Protocol header should only be present for CONNECT for upgrade style CONNECT.
   508→      return absl::InvalidArgumentError(
   509→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Path.get()));
   510→    }
   511→  } else {
   512→    if (!headers.Path()) {
