   521→Http::Status HeaderUtility::checkValidRequestHeaders(const Http::RequestHeaderMap& headers) {
   522→  if (!Runtime::runtimeFeatureEnabled("envoy.reloadable_features.validate_upstream_headers")) {
   523→    return Http::okStatus();
   524→  }
   525→
   526→  const HeaderEntry* invalid_entry = nullptr;
   527→  bool invalid_key = false;
   528→  headers.iterate([&invalid_entry, &invalid_key](const HeaderEntry& header) -> HeaderMap::Iterate {
   529→    if (!HeaderUtility::headerNameIsValid(header.key().getStringView())) {
   530→      invalid_entry = &header;
   531→      invalid_key = true;
   532→      return HeaderMap::Iterate::Break;
   533→    }
   534→
   535→    if (!HeaderUtility::headerValueIsValid(header.value().getStringView())) {
   536→      invalid_entry = &header;
   537→      invalid_key = false;
   538→      return HeaderMap::Iterate::Break;
   539→    }
   540→
   541→    return HeaderMap::Iterate::Continue;
   542→  });
   543→
   544→  if (invalid_entry) {
   545→    // The header key may contain non-printable characters. Escape the key so that the error
   546→    // details can be safely presented.
   547→    const absl::string_view key = invalid_entry->key().getStringView();
   548→    uint64_t extra_length = JsonEscaper::extraSpace(key);
