   586→      envoy::config::core::v3::HttpProtocolOptions::DROP_HEADER) {
   587→    ENVOY_LOG_MISC(debug, "Dropping header with invalid characters in its name: {}", header_name);
   588→    stats.incDroppedHeadersWithUnderscores();
   589→    return HeaderValidationResult::DROP;
