   596→HeaderUtility::HeaderValidationResult
   597→HeaderUtility::validateContentLength(absl::string_view header_value,
   598→                                     bool override_stream_error_on_invalid_http_message,
   599→                                     bool& should_close_connection, size_t& content_length_output) {
   600→  should_close_connection = false;
   601→  std::vector<absl::string_view> values = absl::StrSplit(header_value, ',');
   602→  absl::optional<uint64_t> content_length;
   603→  for (const absl::string_view& value : values) {
   604→    uint64_t new_value;
   605→    if (!absl::SimpleAtoi(value, &new_value) ||
   606→        !std::all_of(value.begin(), value.end(), absl::ascii_isdigit)) {
   607→      ENVOY_LOG_MISC(debug, "Content length was either unparseable or negative");
   608→      should_close_connection = !override_stream_error_on_invalid_http_message;
   609→      return HeaderValidationResult::REJECT;
   610→    }
   611→    if (!content_length.has_value()) {
   612→      content_length = new_value;
   613→      continue;
   614→    }
   615→    if (new_value != content_length.value()) {
   616→      ENVOY_LOG_MISC(
   617→          debug,
   618→          "Parsed content length {} is inconsistent with previously detected content length {}",
   619→          new_value, content_length.value());
   620→      should_close_connection = !override_stream_error_on_invalid_http_message;
   621→      return HeaderValidationResult::REJECT;
   622→    }
   623→  }
   624→  content_length_output = content_length.value();
   625→  return HeaderValidationResult::ACCEPT;
   626→}
