   628→std::vector<absl::string_view>
   629→HeaderUtility::parseCommaDelimitedHeader(absl::string_view header_value) {
   630→  std::vector<absl::string_view> values;
   631→  for (absl::string_view s : absl::StrSplit(header_value, ',')) {
   632→    absl::string_view token = absl::StripAsciiWhitespace(s);
   633→    if (token.empty()) {
   634→      continue;
   635→    }
   636→    values.emplace_back(token);
   637→  }
   638→  return values;
   639→}
