   100→bool HeaderUtility::matchHeaders(const HeaderMap& request_headers,
   101→                                 const std::vector<HeaderDataPtr>& config_headers) {
   102→  // No headers to match is considered a match.
   103→  if (!config_headers.empty()) {
   104→    for (const HeaderDataPtr& cfg_header_data : config_headers) {
   105→      if (!matchHeaders(request_headers, *cfg_header_data)) {
