   282→bool HeaderUtility::rewriteAuthorityForConnectUdp(RequestHeaderMap& headers) {
   283→  // Per RFC 9298, the URI template must only contain ASCII characters in the range 0x21-0x7E.
   284→  absl::string_view path = headers.getPathValue();
   285→  for (char c : path) {
   286→    unsigned char ascii_code = static_cast<unsigned char>(c);
   287→    if (ascii_code < 0x21 || ascii_code > 0x7e) {
   288→      ENVOY_LOG_MISC(warn, "CONNECT-UDP request with a bad character in the path {}", path);
   289→      return false;
   290→    }
   291→  }
   292→
   293→  // Extract target host and port from path using default template.
   294→  if (!absl::StartsWith(path, "/.well-known/masque/udp/")) {
   295→    ENVOY_LOG_MISC(warn, "CONNECT-UDP request path is not a well-known URI: {}", path);
   296→    return false;
   297→  }
   298→
   299→  std::vector<absl::string_view> path_split = absl::StrSplit(path, '/');
   300→  if (path_split.size() != 7 || path_split[4].empty() || path_split[5].empty() ||
   301→      !path_split[6].empty()) {
   302→    ENVOY_LOG_MISC(warn, "CONNECT-UDP request with a malformed URI template in the path {}", path);
   303→    return false;
   304→  }
   305→
   306→  // Utility::PercentEncoding::decode never returns an empty string if the input argument is not
   307→  // empty.
   308→  std::string target_host = Utility::PercentEncoding::decode(path_split[4]);
   309→  // Per RFC 9298, IPv6 Zone ID is not supported.
   310→  if (target_host.find('%') != std::string::npos) {
   311→    ENVOY_LOG_MISC(warn, "CONNECT-UDP request with a non-escpaed char (%) in the path {}", path);
   312→    return false;
   313→  }
   314→  std::string target_port = Utility::PercentEncoding::decode(path_split[5]);
   315→
   316→  // If the host is an IPv6 address, surround the address with square brackets.
   317→  in6_addr sin6_addr;
   318→  bool is_ipv6 = (inet_pton(AF_INET6, target_host.c_str(), &sin6_addr) == 1);
   319→  std::string new_host =
   320→      absl::StrCat((is_ipv6 ? absl::StrCat("[", target_host, "]") : target_host), ":", target_port);
   321→  headers.setHost(new_host);
   322→
   323→  return true;
   324→}
