   337→  absl::optional<quiche::structured_headers::ParameterizedItem> header_item =
   338→      quiche::structured_headers::ParseItem(capsule_protocol[0]->value().getStringView());
   339→  return header_item && header_item->item.is_boolean() && header_item->item.GetBoolean();
   340→}
