   379→  const absl::string_view port_str = original_host.substr(port_start + 1);
   380→  if (port_start == absl::string_view::npos) {
   381→    return false;
   382→  }
   383→  uint32_t port = 0;
   384→  if (!absl::SimpleAtoi(port_str, &port)) {
