   389→
   390→absl::optional<uint32_t> HeaderUtility::stripPortFromHost(RequestHeaderMap& headers,
   391→                                                          absl::optional<uint32_t> listener_port) {
   392→  const absl::string_view original_host = headers.getHostValue();
   393→  const absl::string_view::size_type port_start = getPortStart(original_host);
   394→  if (port_start == absl::string_view::npos) {
   395→    return absl::nullopt;
   396→  }
   397→  const absl::string_view port_str = original_host.substr(port_start + 1);
   398→  uint32_t port = 0;
   399→  if (!absl::SimpleAtoi(port_str, &port)) {
   400→    return absl::nullopt;
   401→  }
   402→  if (listener_port.has_value() && port != listener_port) {
   403→    // We would strip ports only if it is specified and they are the same, as local port of the
   404→    // listener.
   405→    return absl::nullopt;
   406→  }
   407→  const absl::string_view host = original_host.substr(0, port_start);
   408→  headers.setHost(host);
   409→  return port;
   410→}
   411→
   412→absl::string_view::size_type HeaderUtility::getPortStart(absl::string_view host) {
   413→  const absl::string_view::size_type port_start = host.rfind(':');
   414→  if (port_start == absl::string_view::npos) {
   415→    return absl::string_view::npos;
   416→  }
   417→  // According to RFC3986 v6 address is always enclosed in "[]". section 3.2.2.
   418→  const auto v6_end_index = host.rfind(']');
   419→  if (v6_end_index == absl::string_view::npos || v6_end_index < port_start) {
   420→    if ((port_start + 1) > host.size()) {
   421→      return absl::string_view::npos;
   422→    }
   423→    return port_start;
   424→  }
   425→  return absl::string_view::npos;
   426→}
