   489→Http::Status HeaderUtility::checkRequiredRequestHeaders(const Http::RequestHeaderMap& headers) {
   490→  if (!headers.Method()) {
   491→    return absl::InvalidArgumentError(
   492→        absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Method.get()));
   493→  }
   494→  bool is_connect = Http::HeaderUtility::isConnect(headers);
   495→  if (is_connect) {
   496→    if (!headers.Host()) {
   497→      // Host header must be present for CONNECT request.
   498→      return absl::InvalidArgumentError(
   499→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Host.get()));
   500→    }
   501→    if (headers.Path() && !headers.Protocol()) {
   502→      // Path and Protocol header should only be present for CONNECT for upgrade style CONNECT.
   503→      return absl::InvalidArgumentError(
   504→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Protocol.get()));
   505→    }
   506→    if (!headers.Path() && headers.Protocol()) {
   507→      // Path and Protocol header should only be present for CONNECT for upgrade style CONNECT.
   508→      return absl::InvalidArgumentError(
   509→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Path.get()));
   510→    }
   511→  } else {
   512→    if (!headers.Path()) {
   513→      // :path header must be present for non-CONNECT requests.
   514→      return absl::InvalidArgumentError(
   515→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Path.get()));
   516→    }
   517→  }
   518→  return Http::okStatus();
   519→}
   520→
   521→Http::Status HeaderUtility::checkValidRequestHeaders(const Http::RequestHeaderMap& headers) {
   522→  if (!Runtime::runtimeFeatureEnabled("envoy.reloadable_features.validate_upstream_headers")) {
   523→    return Http::okStatus();
   524→  }
   525→
   526→  const HeaderEntry* invalid_entry = nullptr;
   527→  bool invalid_key = false;
   528→  headers.iterate([&invalid_entry, &invalid_key](const HeaderEntry& header) -> HeaderMap::Iterate {
   529→    if (!HeaderUtility::headerNameIsValid(header.key().getStringView())) {
   530→      invalid_entry = &header;
   531→      invalid_key = true;
   532→      return HeaderMap::Iterate::Break;
   533→    }
   534→
   535→    if (!HeaderUtility::headerValueIsValid(header.value().getStringView())) {
   536→      invalid_entry = &header;
   537→      invalid_key = false;
   538→      return HeaderMap::Iterate::Break;
   539→    }
   540→
   541→    return HeaderMap::Iterate::Continue;
   542→  });
   543→
   544→  if (invalid_entry) {
   545→    // The header key may contain non-printable characters. Escape the key so that the error
   546→    // details can be safely presented.
   547→    const absl::string_view key = invalid_entry->key().getStringView();
   548→    uint64_t extra_length = JsonEscaper::extraSpace(key);
   549→    const std::string escaped_key = JsonEscaper::escapeString(key, extra_length);
   550→
   551→    return absl::InvalidArgumentError(
   552→        absl::StrCat("invalid header ", invalid_key ? "name: " : "value for: ", escaped_key));
   553→  }
   554→  return Http::okStatus();
   555→}
