   575→
   576→HeaderUtility::HeaderValidationResult HeaderUtility::checkHeaderNameForUnderscores(
   577→    absl::string_view header_name,
   578→    envoy::config::core::v3::HttpProtocolOptions::HeadersWithUnderscoresAction
   579→        headers_with_underscores_action,
   580→    HeaderValidatorStats& stats) {
   581→  if (headers_with_underscores_action == envoy::config::core::v3::HttpProtocolOptions::ALLOW ||
   582→      !HeaderUtility::headerNameContainsUnderscore(header_name)) {
   583→    return HeaderValidationResult::ACCEPT;
   584→  }
   585→  if (headers_with_underscores_action ==
   586→      envoy::config::core::v3::HttpProtocolOptions::DROP_HEADER) {
   587→    ENVOY_LOG_MISC(debug, "Dropping header with invalid characters in its name: {}", header_name);
   588→    stats.incDroppedHeadersWithUnderscores();
   589→    return HeaderValidationResult::DROP;
   590→  }
   591→  ENVOY_LOG_MISC(debug, "Rejecting request due to header name with underscores: {}", header_name);
   592→  stats.incRequestsRejectedWithUnderscoresInHeaders();
   593→  return HeaderUtility::HeaderValidationResult::REJECT;
   594→}
   595→
   596→HeaderUtility::HeaderValidationResult
   597→HeaderUtility::validateContentLength(absl::string_view header_value,
   598→                                     bool override_stream_error_on_invalid_http_message,
   599→                                     bool& should_close_connection, size_t& content_length_output) {
   600→  should_close_connection = false;
   601→  std::vector<absl::string_view> values = absl::StrSplit(header_value, ',');
   602→  absl::optional<uint64_t> content_length;
   603→  for (const absl::string_view& value : values) {
   604→    uint64_t new_value;
   605→    if (!absl::SimpleAtoi(value, &new_value) ||
   606→        !std::all_of(value.begin(), value.end(), absl::ascii_isdigit)) {
   607→      ENVOY_LOG_MISC(debug, "Content length was either unparseable or negative");
   608→      should_close_connection = !override_stream_error_on_invalid_http_message;
   609→      return HeaderValidationResult::REJECT;
   610→    }
   611→    if (!content_length.has_value()) {
   612→      content_length = new_value;
   613→      continue;
   614→    }
   615→    if (new_value != content_length.value()) {
   616→      ENVOY_LOG_MISC(
   617→          debug,
   618→          "Parsed content length {} is inconsistent with previously detected content length {}",
   619→          new_value, content_length.value());
   620→      should_close_connection = !override_stream_error_on_invalid_http_message;
   621→      return HeaderValidationResult::REJECT;
   622→    }
   623→  }
   624→  content_length_output = content_length.value();
   625→  return HeaderValidationResult::ACCEPT;
   626→}
   627→
   628→std::vector<absl::string_view>
   629→HeaderUtility::parseCommaDelimitedHeader(absl::string_view header_value) {
   630→  std::vector<absl::string_view> values;
   631→  for (absl::string_view s : absl::StrSplit(header_value, ',')) {
   632→    absl::string_view token = absl::StripAsciiWhitespace(s);
   633→    if (token.empty()) {
   634→      continue;
   635→    }
   636→    values.emplace_back(token);
   637→  }
   638→  return values;
   639→}
   640→
   641→absl::string_view HeaderUtility::getSemicolonDelimitedAttribute(absl::string_view value) {
   642→  return absl::StripAsciiWhitespace(StringUtil::cropRight(value, ";"));
   643→}
   644→
   645→std::string HeaderUtility::addEncodingToAcceptEncoding(absl::string_view accept_encoding_header,
   646→                                                       absl::string_view encoding) {
   647→  // Append the content encoding only if it isn't already present in the
   648→  // accept_encoding header. If it is present with a q-value ("gzip;q=0.3"),
   649→  // remove the q-value to indicate that the content encoding setting that we
   650→  // add has max priority (i.e. q-value 1.0).
   651→  std::vector<absl::string_view> newContentEncodings;
   652→  std::vector<absl::string_view> contentEncodings =
   653→      Http::HeaderUtility::parseCommaDelimitedHeader(accept_encoding_header);
   654→  for (absl::string_view contentEncoding : contentEncodings) {
   655→    absl::string_view strippedEncoding =
   656→        Http::HeaderUtility::getSemicolonDelimitedAttribute(contentEncoding);
   657→    if (strippedEncoding != encoding) {
   658→      // Add back all content encodings back except for the content encoding that we want to
   659→      // add. For example, if content encoding is "gzip", this filters out encodings "gzip" and
   660→      // "gzip;q=0.6".
   661→      newContentEncodings.push_back(contentEncoding);
   662→    }
   663→  }
   664→  // Finally add a single instance of our content encoding.
   665→  newContentEncodings.push_back(encoding);
   666→  return absl::StrJoin(newContentEncodings, ",");
   667→}
   668→
   669→bool HeaderUtility::isStandardConnectRequest(const Http::RequestHeaderMap& headers) {
   670→  return headers.getMethodValue() == Http::Headers::get().MethodValues.Connect &&
   671→         headers.getProtocolValue().empty();
   672→}
   673→
   674→bool HeaderUtility::isExtendedH2ConnectRequest(const Http::RequestHeaderMap& headers) {
   675→  return headers.getMethodValue() == Http::Headers::get().MethodValues.Connect &&
   676→         !headers.getProtocolValue().empty();
   677→}
   678→
   679→bool HeaderUtility::isPseudoHeader(absl::string_view header_name) {
   680→  return !header_name.empty() && header_name[0] == ':';
   681→}
   682→
   683→} // namespace Http
   684→} // namespace Envoy
