   358→void HeaderUtility::stripTrailingHostDot(RequestHeaderMap& headers) {
   359→  auto host = headers.getHostValue();
   360→  // If the host ends in a period, remove it.
   361→  auto dot_index = host.rfind('.');
   362→  if (dot_index == std::string::npos) {
   363→    return;
   364→  } else if (dot_index == (host.size() - 1)) {
   365→    host.remove_suffix(1);
   366→    headers.setHost(host);
   367→    return;
   368→  }
   369→  // If the dot is just before a colon, it must be preceding the port number.
   370→  // IPv6 addresses may contain colons or dots, but the dot will never directly
   371→  // precede the colon, so this check should be sufficient to detect a trailing port number.
   372→  if (host[dot_index + 1] == ':') {
   373→    headers.setHost(absl::StrCat(host.substr(0, dot_index), host.substr(dot_index + 1)));
   374→  }
   375→}
