   428→constexpr bool isInvalidToken(unsigned char c) {
   429→  if (c == '!' || c == '|' || c == '~' || c == '*' || c == '+' || c == '-' || c == '.' ||
   430→      // #, $, %, &, '
   431→      (c >= '#' && c <= '\'') ||
   432→      // [0-9]
   433→      (c >= '0' && c <= '9') ||
   434→      // [A-Z]
   435→      (c >= 'A' && c <= 'Z') ||
   436→      // ^, _, `, [a-z]
   437→      (c >= '^' && c <= 'z')) {
   438→    return false;
   439→  }
   440→  return true;
   441→}
