  1017→    bool failure = !validation_result.ok();
  1018→    bool redirect = false;
  1019→    bool is_grpc = Grpc::Common::hasGrpcContentType(*request_headers_);
  1020→    std::string failure_details(validation_result.details());
  1021→    if (!failure) {
  1022→      auto transformation_result = header_validator_->transformRequestHeaders(*request_headers_);
  1023→      failure = !transformation_result.ok();
  1024→      redirect = transformation_result.action() ==
  1025→                 Http::ServerHeaderValidator::RequestHeadersTransformationResult::Action::Redirect;
  1026→      failure_details = std::string(transformation_result.details());
  1027→      if (redirect && !is_grpc) {
  1028→        connection_manager_.stats_.named_.downstream_rq_redirected_with_normalized_path_.inc();
  1029→      } else if (failure) {
  1030→        connection_manager_.stats_.named_.downstream_rq_failed_path_normalization_.inc();
  1031→      }
  1032→    }
  1033→    if (failure) {
  1034→      std::function<void(ResponseHeaderMap & headers)> modify_headers;
  1035→      Code response_code = failure_details == Http1ResponseCodeDetail::get().InvalidTransferEncoding
  1036→                               ? Code::NotImplemented
  1037→                               : Code::BadRequest;
  1038→      absl::optional<Grpc::Status::GrpcStatus> grpc_status;
  1039→      if (redirect && !is_grpc) {
