  Code response_code = Code::BadRequest;
  absl::optional<Grpc::Status::GrpcStatus> grpc_status;
  if (Grpc::Common::hasGrpcContentType(*request_headers_)) {
    grpc_status = Grpc::Status::WellKnownGrpcStatus::Internal;
  }

