    26→/**
    27→ * Check Issuer specified in Provider
    28→ */
    29→class JwtIssuerChecker {
    30→public:
    31→  // add a specified issuer from JwtProvider.
    32→  void add(const std::string& issuer) {
    33→    // If a specified issuer is empty, it means to allow all issuers.
    34→    if (issuer.empty()) {
    35→      allow_all_ = true;
    36→    } else {
    37→      specified_issuers_.insert(issuer);
    38→    }
    39→  }
    40→
    41→  // check if a jwt issuer is allowed
    42→  bool check(const std::string& jwt_issuer) const {
    43→    if (allow_all_) {
    44→      return true;
    45→    }
    46→    return specified_issuers_.find(jwt_issuer) != specified_issuers_.end();
    47→  }
    48→
    49→private:
    50→  // If true, all issuers are ok
    51→  bool allow_all_{false};
    52→  // Only these specified issuers are allowed.
    53→  absl::flat_hash_set<std::string> specified_issuers_;
    54→};
